#include <iostream>
#include <cmath>
using namespace std;
int main() {
	int n, m, k, p, T;
	cin >> T;
	for (int i = 0; i < T; i++) {
		cin >> n >> m >> k >> p;
		if (k > m) {
			cout << "Divide" << "\n";
		}
		else if (ceil((n * m * 1.0 - p) / n) >= k) {

			cout << "Together" << "\n";
		}
		else {
			cout << "Chance" << "\n";
		}
	}
	


	return 0;
}
